public class DigitCount {
    public static void main(String[] args) {
        System.out.println("Count of 2 in 12321: " + countDigit(12321, 2));
        System.out.println("Count of 5 in 55555: " + countDigit(55555, 5));
        System.out.println("Count of 9 in 12345: " + countDigit(12345, 9));
    }

    public static int countDigit(int number, int target) {
        if (number == 0) {
            return 0;
        }
        int lastDigit = number % 10;
        int countOfRest = countDigit(number / 10, target);
        if (lastDigit == target) {
            return 1 + countOfRest;
        }
        return countOfRest;
    }
}

exercises.instructions:
Write a class `ReverseNumber` with method `reverse(int n)` that returns n with its digits reversed.

Examples:
- reverse(1234) = 4321
- reverse(700) = 7 (leading zeros dropped)
- reverse(5) = 5

This is tricky! Use a helper method with an accumulator parameter:

```java
public static int reverse(int n) {
    return reverseHelper(n, 0);
}

public static int reverseHelper(int n, int reversed) {
    if (n == 0) return reversed;
    // build reversed by shifting and adding last digit
    return reverseHelper(n / 10, reversed * 10 + n % 10);
}
```

Expected output:
reverse(1234) = 4321
reverse(700) = 7
reverse(5) = 5

exercises.expected_solution:
public class ReverseNumber {
    public static void main(String[] args) {
        System.out.println("reverse(1234) = " + reverse(1234));
        System.out.println("reverse(700) = " + reverse(700));
        System.out.println("reverse(5) = " + reverse(5));
    }

    public static int reverse(int n) {
        return reverseHelper(n, 0);
    }

    public static int reverseHelper(int n, int reversed) {
        if (n == 0) {
            return reversed;
        }
        return reverseHelper(n / 10, reversed * 10 + n % 10);
    }
}

public class Comparison {
    public static void main(String[] args) {
        int n = 10;
        int iterResult = sumIterative(n);
        int recurResult = sumRecursive(n);

        System.out.println("Iterative sum(" + n + "): " + iterResult);
        System.out.println("Recursive sum(" + n + "): " + recurResult);
        System.out.println("Match: " + (iterResult == recurResult));
    }

    public static int sumIterative(int n) {
        int total = 0;
        for (int i = 1; i <= n; i++) {
            total += i;
        }
        return total;
    }

    public static int sumRecursive(int n) {
        if (n == 0) return 0;
        return n + sumRecursive(n - 1);
    }
}

public class GCD {
    public static void main(String[] args) {
        System.out.println("gcd(48, 36) = " + gcd(48, 36));
        System.out.println("gcd(100, 75) = " + gcd(100, 75));
        System.out.println("gcd(17, 5) = " + gcd(17, 5));
        System.out.println("gcd(1071, 462) = " + gcd(1071, 462));
    }

    public static int gcd(int a, int b) {
        if (b == 0) {
            return a;
        }
        return gcd(b, a % b);
    }
}
